---- MODULE KVStore ----
EXTENDS Integers, Sequences, FiniteSets
CONSTANTS NULL, N

VARIABLES store

Init == store = [k \in 0..N |-> NULL];

Next == \/ /\ \E k \in 0..N : \E v \in 0..N : store' = [store EXCEPT ![k] = v];
        \/ /\ \E k \in 0..N : store' = [store EXCEPT ![k] = NULL];
        \/ store' = store

Spec == Init /\ [][Next]_<<store>>

====

---- MODULE BinaryCounter ----
EXTENDS Integers, Sequences

VARIABLES counter

Init == counter = 0;

Next == /\ counter' = (counter + 1) % 4;

Spec == Init /\ [][Next]_<<counter>>;

====

---- MODULE Mutex ----
EXTENDS Naturals, FiniteSets

CONSTANT Procs

\* owner is a SET of at most one process; empty means free.
VARIABLE owner

vars == << owner >>;

Init == owner = {};

\* Acquire is unconditional when free.
Lock(p) == /\ owner = {};
           /\ owner' = {p}

\* TryLock may succeed (when free) or fail (no state change).
TryLockSucceed(p) == /\ owner = {}
                     /\ owner' = {p}

TryLockFail(p) == /\ owner # {}
                  /\ UNCHANGED owner

\* Only the current owner may release.
Unlock(p) == /\ owner = {p}
             /\ owner' = {}

Next == \/ \E p \in Procs : Lock(p)
        \/ \E p \in Procs : TryLockSucceed(p)
        \/ \E p \in Procs : TryLockFail(p)
        \/ \E p \in Procs : Unlock(p)

Spec == Init /\ [][Next]_vars

\* Safety: at most one owner at any time.
MutexSafe == Cardinality(owner) <= 1

TypeOK == /\ owner \subseteq Procs
          /\ MutexSafe
====

---- MODULE Register ----
EXTENDS Integers, Sequences, FiniteSets

VARIABLE value

Init == value = 0;

Next == \/ value' = value;
      \/ value' = 0

Spec == Init /\ [][Next]_<<value>> ====;
==============================================================================

---- MODULE DekkersAlgorithm ----
EXTENDS Integers, Sequences

VARIABLE turn, wants

Init == /\ turn \in {0, 1}
        /\ wants = <<FALSE, FALSE>>

Next == FALSE
Spec == Init /\ [][Next]_<<turn, wants>>

TypeOK == /\ turn \in {0, 1}
          /\ wants \in {<<FALSE, FALSE>>, <<FALSE, TRUE>>, <<TRUE, FALSE>>, <<TRUE, TRUE>>}

====

---- MODULE Dekker ----
EXTENDS Integers, Sequences, FiniteSets

VARIABLES turn, wants

Init == /\ turn \in {0,1}
        /\ wants \in SUBSET {0,1}
        /\ turn \in {0,1}
        /\ wants \subseteq {0,1}

Next == \/ /\ turn' = 1 - turn
          /\ wants' = {0,1}
        \/ /\ turn' = turn
          /\ wants' = {0,1} \ {turn}
          /\ turn \in {0,1}
          /\ wants \subseteq {0,1}

Spec == Init /\ [][Next]_<<turn, wants>>

TypeOK == TRUE
====

